+import { describe, expect, it } from "vitest";
+import { activeGate, workbenchData } from "../data/fixtures";
+
+describe("workbench fixtures", () => {
+  it("answers the four first-screen questions", () => {
+    expect(workbenchData.projects.length).toBeGreaterThanOrEqual(3);
+    expect(workbenchData.agentRuns.some((run) => run.status === "running")).toBe(true);
+    expect(activeGate(workbenchData)?.status).toBe("waiting");
+    expect(workbenchData.engineeringFeedback.diffFiles.length).toBeGreaterThan(0);
+    expect(workbenchData.engineeringFeedback.testSummary.passRate).toBe(92);
+  });
