+
+```ts
+export type Status = "ok" | "busy" | "warning" | "waiting" | "running" | "done" | "queued";
+
+export interface Project {
+  id: string;
+  name: string;
+  branch: string;
+  status: Status;
+  workflowTemplateId: string;
+  workflowOverrides: WorkflowOverride[];
+}
+
