+  version: string;
+  steps: WorkflowStep[];
+}
+
+export interface WorkflowOverride {
+  stepId: string;
+  roleId?: string;
+  gate?: "auto" | "manual";
+}
+
+export interface Task {
+  id: string;
+  projectId: string;
+  title: string;
+  description: string;
+  priority: "P0" | "P1" | "P2";
+  status: Status;
+}
+
+export interface AgentRun {
+  id: string;
+  taskId: string;
+  roleId: string;
+  title: string;
+  summary: string;
+  timestamp: string;
+  status: Status;
+}
+
+export interface ManualGate {
+  id: string;
+  taskId: string;
+  title: string;
+  description: string;
+  status: "waiting" | "continued" | "rerun" | "reassigned" | "stopped";
+}
+
+export interface EngineeringFeedback {
+  diffFiles: Array<{ path: string; additions: number; summary: string }>;
+  testSummary: { passRate: number; status: Status; summary: string };
+  memorySuggestion: string;
+}
+
