+  { id: "settings", label: "设置中心", symbol: "S" },
+];
+
+export function AppShell({ data, view, onViewChange, children }: AppShellProps) {
+  return (
+    <div className="app-shell">
+      <aside className="sidebar" aria-label="主导航">
+        <div className="brand">
+          <div className="brand-mark">A</div>
