```tsx
import { useMemo, useState } from "react";
import type { WorkbenchData } from "../domain/workbench";

interface WorkspaceDashboardProps {
  data: WorkbenchData;
}

export function WorkspaceDashboard({ data }: WorkspaceDashboardProps) {
  const [gateMessage, setGateMessage] = useState("");
  const runningAgents = data.agentRuns.filter((run) => run.status === "running").length;
  const waitingGate = data.manualGates.find((gate) => gate.status === "waiting");
  const activeTask = data.tasks.find((task) => task.id === waitingGate?.taskId) ?? data.tasks[0];
  const template = useMemo(() => data.workflowTemplates[0], [data.workflowTemplates]);

  return (
    <div className="workspace">
      <section className="hero-row">
        <article className="panel">
          <div className="panel-header">
            <div>
              <h2>多项目 Agent 控制台</h2>
              <span>同时管理任务、分支、worktree、Agent Run 与人工 gate</span>
            </div>
          </div>
          <div className="metrics">
            <div className="metric"><span>活跃项目</span><strong>{data.projects.length}</strong><small>2 个有运行任务</small></div>
            <div className="metric"><span>运行 Agent</span><strong>{runningAgents}</strong><small>1 个等待人工确认</small></div>
            <div className="metric"><span>测试通过率</span><strong>{data.engineeringFeedback.testSummary.passRate}%</strong><small>最近 24 小时</small></div>
            <div className="metric"><span>待合并分支</span><strong>5</strong><small>包含 2 个 UI 任务</small></div>
          </div>
        </article>
      </section>

      <section className="board">
        <article className="panel">
          <div className="panel-header"><h3>项目任务树</h3></div>
          <div className="task-tree">
            {data.tasks.map((task) => (
              <div className={`task-card ${task.id === activeTask.id ? "active" : ""}`} key={task.id}>
                <strong>{task.title}</strong>
                <p>{task.description}</p>
                <div className="badge-row">
                  <span className="badge blue">{task.priority}</span>
                  <span className="badge">{task.status}</span>
                </div>
              </div>
            ))}
          </div>
        </article>

        <article className="panel">
          <div className="panel-header">
            <div>
              <h3>当前任务执行区</h3>
              <span>{activeTask.title} / frontend-agent-run-1042</span>
            </div>
          </div>
          <div className="stepper">
            {template.steps.map((step, index) => (
              <div className={`step ${index < 2 ? "done" : index === 2 ? "active" : ""}`} key={step.id}>
                <small>{String(index + 1).padStart(2, "0")}</small>
                <strong>{step.name}</strong>
                <span className="badge">{step.gate}</span>
              </div>
            ))}
          </div>
          <div className="timeline">
            {data.agentRuns.map((run) => (
              <div className="run-item" key={run.id}>
                <div className="run-avatar">{run.roleId.slice(0, 2).toUpperCase()}</div>
                <div><h4>{run.title}</h4><p>{run.summary}</p></div>
                <div className="time">{run.timestamp}</div>
              </div>
            ))}
          </div>
          {waitingGate && (
            <div className="gate">
              <div>
                <strong>{waitingGate.title}</strong>
                <span>{waitingGate.description}</span>
                {gateMessage && <p className="gate-message">{gateMessage}</p>}
              </div>
              <div className="gate-actions">
                <button className="ghost" type="button" onClick={() => setGateMessage("Gate 已重跑，重新进入 UI 评审。")}>重跑</button>
                <button className="ghost" type="button" onClick={() => setGateMessage("Gate 已改派给 UI Agent。")}>改派</button>
                <button className="primary" type="button" onClick={() => setGateMessage("Gate 已继续，下一步进入前端实现。")}>继续</button>
              </div>
            </div>
          )}
        </article>

        <article className="panel inspector">
          <div className="panel-header"><h3>工程反馈</h3></div>
          {data.engineeringFeedback.diffFiles.map((file) => (
            <div className="mini-box" key={file.path}>
              <strong>{file.path}</strong>
              <span>+{file.additions} / {file.summary}</span>
            </div>
          ))}
          <div className="mini-box">
            <strong>测试</strong>
            <span>{data.engineeringFeedback.testSummary.summary}</span>
          </div>
          <div className="mini-box">
            <strong>记忆建议</strong>
            <span>{data.engineeringFeedback.memorySuggestion}</span>
          </div>
        </article>
      </section>
    </div>
  );
}
```

